SELECT package_size, temperature_requirements
FROM packaging
WHERE ndc_11 = '58160-0830-01';

SELECT alias_name
FROM product_aliases
WHERE ndc_11 = '58160-0830-01';

SELECT route_name
FROM administration_routes
WHERE route_id = 1;

SELECT route_name
FROM administration_routes
WHERE recommended_equipment LIKE '%Syringe%';

SELECT DISTINCT c1.category_name
FROM categories c1
JOIN categories c2 ON c1.category_id = c2.parent_category_id;

SELECT COUNT(alias_id) AS alias_count
FROM product_aliases
WHERE ndc_11 = '58160-0830-01';

SELECT ndc_11
FROM packaging
WHERE shelf_life = (SELECT MAX(shelf_life) FROM packaging);

SELECT major_class_name
FROM major_classes
WHERE major_class_id = 1;

SELECT route_name, description, recommended_equipment
FROM administration_routes
ORDER BY route_name ASC;

SELECT package_type
FROM packaging
WHERE package_id = 1;
